// // This is a 4-bit binary counter that decrements the output 'q' on every positive edge of the clock. It has an active low synchronous reset that sets the output to 15.
module top_module(
	input clk,
	input reset,
	output reg [3:0] q);always @(posedge clk or posedge reset)
	if (reset)
		q <= 4'b0000;
	else
		q <= q + 1;

endmodule
